const item = $input.first();
const mcp  = item.json;
const prev = $('Set Input').first().json;

let identityBlock = '';
let clientStatus  = 'new';
let clientProfile = {};

if (mcp.found === true || mcp.client_id) {
  clientStatus = mcp.status === 'inactive' ? 'inactive_former' : 'existing';
  clientProfile = {
    client_id:       mcp.client_id || '',
    full_name:       mcp.full_name || prev.sender_name,
    status:          mcp.status   || 'active',
    lots:            mcp.lots     || [],
    account_manager: mcp.account_manager || '',
    levy_status:     mcp.levy_status     || 'unknown',
    open_requests:   mcp.open_requests   || 0,
    portal_access:   mcp.portal_access   || false
  };

  const lotsSummary = clientProfile.lots.length > 0
    ? clientProfile.lots.map(l => `Lot ${l.lot_number} at ${l.building} (${l.role})`).join('; ')
    : 'No lots on file';

  identityBlock = [
    `## Verified Client Profile`,
    `- Client ID: ${clientProfile.client_id}`,
    `- Name: ${clientProfile.full_name}`,
    `- Account Status: ${clientProfile.status}`,
    `- Lots: ${lotsSummary}`,
    `- Account Manager: ${clientProfile.account_manager || 'Unassigned'}`,
    `- Levy Status: ${clientProfile.levy_status}`,
    `- Open Requests: ${clientProfile.open_requests}`,
    `- Portal Access: ${clientProfile.portal_access ? 'Yes' : 'No'}`
  ].join('\n');

} else {
  clientStatus  = 'new';
  identityBlock = [
    `## Client Identity`,
    `- Status: NOT FOUND in database (treat as new enquiry)`,
    `- Name provided: ${prev.sender_name  || 'Not given'}`,
    `- Email provided: ${prev.sender_email || 'Not given'}`
  ].join('\n');
}

return [{
  json: {
    ...prev,
    client_status:  clientStatus,
    client_profile: clientProfile,
    identity_block: identityBlock
  }
}];

// Merge identity context + Sheets KB rows into a single enriched payload
// for the AI agent prompt

const sheetsItems = $input.all();
const prev = $('Build Identity Context').first().json;

// Build a compact text block from all sheet rows (cap at 20 most recent to avoid context overflow)
const rows = sheetsItems
  .map(i => i.json)
  .filter(r => r.category && r.original_message)
  .slice(-20); // take the 20 most recent rows

let kbBlock = '';

if (rows.length > 0) {
  const rowText = rows.map((r, idx) => [
    `### Past Enquiry ${idx + 1}`,
    `- Category: ${r.category}${r.subcategory ? ' — ' + r.subcategory : ''}`,
    `- Urgency: ${r.urgency}`,
    `- Client Status: ${r.client_status}`,
    `- Original Message: ${r.original_message}`,
    `- Recommended Action: ${r.recommended_action}`,
    `- Suggested Response: ${r.suggested_response}`
  ].join('\n')).join('\n\n');

  kbBlock = [
    `## Past Enquiries Knowledge Base (${rows.length} records — use the most similar ones to inform your classification and response):`,
    rowText,
    ``,
    `> INSTRUCTION: Find the 1–3 past enquiries most similar to the current message. Use their Recommended Action and Suggested Response as your primary basis — adapt, do not copy verbatim. Set action_source to "sheets_kb".`
  ].join('\n');
} else {
  kbBlock = [
    `## Past Enquiries Knowledge Base: No records found.`,
    `> INSTRUCTION: No past data available. Generate classification and recommended action from strata industry first principles. Set action_source to "ai_reasoning".`
  ].join('\n');
}

return [{
  json: {
    ...prev,
    kb_block: kbBlock,
    has_kb: rows.length > 0
  }
}];

const items = $input.all();
const outputs = [];

for (const item of items) {
  try {
    let aiResponse = item.json.response || item.json.output || item.json.text || '';

    // Strip code fences
    aiResponse = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    // Extract JSON block if wrapped in extra text
    const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
    if (jsonMatch) aiResponse = jsonMatch[0];

    const parsed = JSON.parse(aiResponse);

    // Required fields check
    const required = ['category', 'urgency', 'confidence', 'client_status', 'summary', 'suggested_response', 'recommended_action', 'action_source'];
    const missing = required.filter(f => !parsed[f]);
    if (missing.length > 0) throw new Error(`Missing fields: ${missing.join(', ')}`);

    // Normalise optional fields
    parsed.subcategory         = parsed.subcategory || '';
    parsed.client_id           = parsed.client_id   || null;
    parsed.key_details         = parsed.key_details         || [];
    parsed.follow_up_questions = parsed.follow_up_questions || [];
    parsed.routing             = parsed.routing             || 'General Queue';

    const prev = $('Merge Identity + KB Context').first().json;

    outputs.push({
      json: {
        success: true,
        data: parsed,
        meta: {
          original_message: prev.message        || '',
          sender_name:      prev.sender_name    || '',
          sender_email:     prev.sender_email   || '',
          channel:          prev.channel        || 'web',
          client_profile:   prev.client_profile || {},
          has_kb_context:   prev.has_kb         || false,
          processed_at:     new Date().toISOString()
        }
      }
    });

  } catch (error) {
    const prev = $('Merge Identity + KB Context').first().json;
    outputs.push({
      json: {
        success: false,
        error: error.message,
        data: {
          category:            'General Question',
          subcategory:         '',
          urgency:             'Medium',
          confidence:          0,
          client_status:       prev.client_status             || 'unknown',
          client_id:           prev.client_profile?.client_id || null,
          summary:             'Classification failed — manual review required',
          key_details:         [],
          suggested_response:  'Thank you for your enquiry. A member of our team will be in touch shortly.',
          recommended_action:  'Manual review required — AI classification failed. Assign to senior staff.',
          action_source:       'fallback',
          routing:             'General Queue',
          follow_up_questions: []
        },
        meta: {
          original_message: prev.message    || '',
          processed_at:     new Date().toISOString()
        }
      }
    });
  }
}

return outputs;
